//  PinballView.swift
//  Roll Along — Pinball minigame (SpriteKit).
//
//  The table geometry is a TRACE of Mac's hand-drawn map: walls were detected
//  from the sketch's black/white boundary, vectorised into smooth polylines, and
//  the element positions (bumpers, slingshots, flippers, ball, drain) read off
//  the drawing. All of that lives in the embedded `GameTable.json` below
//  (generated by tools/pinball/gen_table.py) and is decoded at runtime — so the
//  layout is data-driven and no new project files are needed.
//
//  The playfield is letterboxed at the sketch's true aspect (never stretched).
//  Physics-feel constants near the top of PinballScene want a device playtest.

import SwiftUI
import SpriteKit

// MARK: - Observable bridge (scene → SwiftUI HUD)

final class PinballModel: ObservableObject {
    @Published var score          = 0
    @Published var ballsLeft       = 3
    @Published var awaitingLaunch  = true
    @Published var isOver          = false
}

// MARK: - Decoded table data

struct GameTable: Codable {
    struct Bumper: Codable { let x, y, r: Double }
    struct Flip: Codable { let pivot: [Double]; let tip: [Double]; let side: String }
    struct P: Codable { let x, y: Double }
    struct Drain: Codable { let x, y, w, h: Double }

    let aspect: Double
    let walls: [[[Double]]]
    let bumpers: [Bumper]
    let slings: [[[Double]]]
    let flippers: [Flip]
    let ballStart: P
    let drain: Drain
    let dropHole: P

    static let shared: GameTable = {
        let data = Data(json.utf8)
        return try! JSONDecoder().decode(GameTable.self, from: data)
    }()

