// MARK: - SwiftUI host

struct PinballView: View {
    @EnvironmentObject var gameState: GameState
    @EnvironmentObject var nav: Navigator

    @StateObject private var model = PinballModel()
    @State private var scene = PinballScene(size: CGSize(width: 393, height: 760))
    @State private var didSubmit = false

    var body: some View {
        ZStack {
            Color(white: 0.04).ignoresSafeArea()
            SpriteView(scene: scene, options: [.ignoresSiblingOrder])
                .ignoresSafeArea()

            VStack {
                topBar
                Spacer()
                if model.awaitingLaunch && !model.isOver {
                    Text("Tap to launch")
                        .font(.system(.headline, design: .rounded).weight(.bold))
                        .foregroundStyle(.white)
                        .padding(.horizontal, 18).padding(.vertical, 10)
                        .background(Capsule().fill(.black.opacity(0.5)))
                        .padding(.bottom, 54)
                }
            }
            if model.isOver { gameOverOverlay }
        }
        .navigationBarBackButtonHidden(true)
        .toolbar(.hidden, for: .navigationBar)
        .onAppear {
            scene.scaleMode = .resizeFill
            scene.model = model
            scene.hapticsEnabled = gameState.hapticsEnabled
        }
        .onChange(of: model.isOver) { _, over in if over { submitScore() } }
    }

    private var topBar: some View {
        HStack {
            Button { nav.goHome() } label: {
                Image(systemName: "xmark")
                    .font(.system(size: 15, weight: .bold)).foregroundStyle(.white)
                    .frame(width: 34, height: 34).background(Circle().fill(.black.opacity(0.45)))
            }
            Spacer()
            VStack(spacing: 0) {
                Text("\(model.score)")
                    .font(.system(.title2, design: .rounded).weight(.heavy))
                    .monospacedDigit().foregroundStyle(.white)
                Text("SCORE").font(.system(size: 10, weight: .bold)).tracking(2)
                    .foregroundStyle(Color(white: 0.6))
            }
            Spacer()
            HStack(spacing: 5) {
                ForEach(0..<3, id: \.self) { i in
                    Circle().fill(i < model.ballsLeft ? Color.white : Color(white: 0.3))
                        .frame(width: 9, height: 9)
                }
            }.frame(width: 34)
        }
        .padding(.horizontal, 16).padding(.top, 8)
    }

    private var gameOverOverlay: some View {
        ZStack {
            Color.black.opacity(0.7).ignoresSafeArea()
            VStack(spacing: 18) {
                Text("Game Over")
                    .font(.system(.largeTitle, design: .rounded).weight(.heavy)).foregroundStyle(.white)
                VStack(spacing: 2) {
                    Text("\(model.score)")
                        .font(.system(size: 52, design: .rounded).weight(.black))
                        .monospacedDigit().foregroundStyle(Color(red: 1.0, green: 0.84, blue: 0.30))
                    Text("FINAL SCORE").font(.system(size: 11, weight: .bold)).tracking(2)
                        .foregroundStyle(Color(white: 0.6))
                }
                HStack(spacing: 14) {
                    Button { playAgain() } label: {
                        Text("Play again").font(.system(.body, design: .rounded).weight(.bold))
                            .foregroundStyle(.black).padding(.horizontal, 22).padding(.vertical, 12)
                            .background(Capsule().fill(.white))
                    }
                    Button { nav.goHome() } label: {
                        Text("Home").font(.system(.body, design: .rounded).weight(.bold))
                            .foregroundStyle(.white).padding(.horizontal, 22).padding(.vertical, 12)
                            .background(Capsule().fill(Color(white: 0.22)))
                    }
                }
            }
        }
    }

    private func submitScore() {
        guard !didSubmit else { return }
        didSubmit = true
        let s = model.score
        let banked = s / 250
        if banked > 0 { gameState.addCoins(banked) }
        gameState.recordPinballScore(s)
        if gameState.hapticsEnabled { Haptics.success() }
    }

    private func playAgain() { didSubmit = false; scene.resetGame() }
}

// MARK: - SpriteKit scene

final class PinballScene: SKScene, SKPhysicsContactDelegate {

    // ── Tuning (playtest these) ───────────────────────────────────────────
    private let gravityY:        CGFloat = -6.0
    private let ballRadiusFrac:  CGFloat = 0.017   // of field width
    private let ballMass:        CGFloat = 0.06
    private let launchSpeedFrac:  CGFloat = 1.15   // launch speed = this × field height
    private let bumperImpulse:   CGFloat = 4.0
    private let slingImpulse:    CGFloat = 3.0
    private let flipDuration:    Double  = 0.04
    private let flipSwing:       CGFloat = 0.55    // radians the bat sweeps up

    private let bumperScore = 100
    private let slingScore  = 10

    private struct Cat {
        static let ball:    UInt32 = 1 << 0
        static let wall:    UInt32 = 1 << 1
        static let flipper: UInt32 = 1 << 2
        static let bumper:  UInt32 = 1 << 3
        static let sling:   UInt32 = 1 << 4
        static let drain:   UInt32 = 1 << 5
    }

    weak var model: PinballModel?
    var hapticsEnabled = true

    private var score = 0
    private var ballsLeft = 3
    private var awaitingLaunch = true
    private var isOver = false
    private var built = false

    private var field = CGRect.zero
    private var ball: SKShapeNode?
    private var leftFlipper: SKShapeNode?
    private var rightFlipper: SKShapeNode?
    private var leftRest: CGFloat = 0, leftFlip: CGFloat = 0
    private var rightRest: CGFloat = 0, rightFlip: CGFloat = 0

    private var fw: CGFloat { field.width }
    private var ballRadius: CGFloat { fw * ballRadiusFrac }

    /// fx,fy in 0..1 of the playfield (fy top→bottom) → scene point (y up).
    private func pt(_ fx: Double, _ fy: Double) -> CGPoint {
        CGPoint(x: field.minX + CGFloat(fx) * field.width,
                y: field.maxY - CGFloat(fy) * field.height)
    }
    private func pt(_ a: [Double]) -> CGPoint { pt(a[0], a[1]) }

    override func didMove(to view: SKView) {
        backgroundColor = SKColor(red: 0.07, green: 0.07, blue: 0.10, alpha: 1)
        physicsWorld.gravity = CGVector(dx: 0, dy: gravityY)
        physicsWorld.contactDelegate = self
    }

    override func update(_ currentTime: TimeInterval) {
        if !built && size.width > 4 {
            built = true
            computeField()
            buildTable()
            spawnBall()
            pushModel()
        }
    }

    func resetGame() {
        removeAllChildren()
        ball = nil; leftFlipper = nil; rightFlipper = nil
        score = 0; ballsLeft = 3; awaitingLaunch = true; isOver = false
        buildTable(); spawnBall(); pushModel()
    }

    // MARK: Build

    private func computeField() {
        let a = CGFloat(GameTable.shared.aspect)        // height / width
        var w = size.width, h = w * a
        if h > size.height { h = size.height; w = h / a }
        field = CGRect(x: (size.width - w) / 2, y: (size.height - h) / 2, width: w, height: h)
    }

    private func buildTable() {
        buildWalls(); buildBumpers(); buildSlings(); buildFlippers(); buildDrain()
    }

    private func buildWalls() {
        for wall in GameTable.shared.walls where wall.count >= 2 {
            let path = CGMutablePath()
            path.addLines(between: wall.map { pt($0) })
            path.closeSubpath()
            let node = SKShapeNode(path: path)
            node.strokeColor = SKColor(white: 0.62, alpha: 1)
            node.lineWidth = 2
            node.lineJoin = .round
            let body = SKPhysicsBody(edgeChainFrom: path)
            body.categoryBitMask = Cat.wall
            body.friction = 0.08
            body.restitution = 0.18
            node.physicsBody = body
            addChild(node)
        }
    }

    private func buildBumpers() {
        for b in GameTable.shared.bumpers {
            let r = CGFloat(b.r) * fw
            let node = SKShapeNode(circleOfRadius: r)
            node.fillColor = SKColor(red: 0.95, green: 0.55, blue: 0.15, alpha: 1)
            node.strokeColor = .white; node.lineWidth = 2
            node.position = pt(b.x, b.y); node.name = "bumper"
            let cap = SKShapeNode(circleOfRadius: r * 0.42)
            cap.fillColor = SKColor(white: 0.1, alpha: 1); cap.strokeColor = .clear
            node.addChild(cap)
            let body = SKPhysicsBody(circleOfRadius: r)
            body.isDynamic = false; body.restitution = 0.5
            body.categoryBitMask = Cat.bumper
            body.collisionBitMask = Cat.ball; body.contactTestBitMask = Cat.ball
            node.physicsBody = body
            addChild(node)
        }
    }

    private func buildSlings() {
        for tri in GameTable.shared.slings where tri.count == 3 {
            let path = CGMutablePath()
            path.addLines(between: tri.map { pt($0) })
            path.closeSubpath()
            let node = SKShapeNode(path: path)
            node.fillColor = SKColor(red: 0.90, green: 0.28, blue: 0.34, alpha: 1)
            node.strokeColor = .white; node.lineWidth = 1; node.name = "sling"
            let body = SKPhysicsBody(polygonFrom: path)
            body.isDynamic = false; body.restitution = 0.4
            body.categoryBitMask = Cat.sling
            body.collisionBitMask = Cat.ball; body.contactTestBitMask = Cat.ball
            node.physicsBody = body
            addChild(node)
        }
    }

    private func buildFlippers() {
        for f in GameTable.shared.flippers {
            let pivot = pt(f.pivot), tip = pt(f.tip)
            let dx = tip.x - pivot.x, dy = tip.y - pivot.y
            let len = max(hypot(dx, dy), 1)
            let rest = atan2(dy, dx)
            let thick = ballRadius * 1.3
            let node = SKShapeNode(rect: CGRect(x: 0, y: -thick / 2, width: len, height: thick),
                                   cornerRadius: thick / 2)
            node.fillColor = SKColor(red: 0.25, green: 0.55, blue: 1.0, alpha: 1)
            node.strokeColor = .white; node.lineWidth = 1
            node.position = pivot; node.zRotation = rest
            let body = SKPhysicsBody(rectangleOf: CGSize(width: len, height: thick),
                                     center: CGPoint(x: len / 2, y: 0))
            body.isDynamic = false
            body.categoryBitMask = Cat.flipper
            body.collisionBitMask = Cat.ball
            node.physicsBody = body
            addChild(node)
            if f.side == "L" { leftFlipper = node; leftRest = rest; leftFlip = rest + flipSwing }
            else { rightFlipper = node; rightRest = rest; rightFlip = rest - flipSwing }
        }
    }

    private func buildDrain() {
        let d = GameTable.shared.drain
        let node = SKNode()
        node.position = pt(d.x, d.y)
        let body = SKPhysicsBody(rectangleOf: CGSize(width: CGFloat(d.w) * fw,
                                                     height: CGFloat(d.h) * field.height))
        body.isDynamic = false
        body.categoryBitMask = Cat.drain
        body.collisionBitMask = 0; body.contactTestBitMask = Cat.ball
        node.physicsBody = body
        addChild(node)
    }

    // MARK: Ball

    private func spawnBall() {
        ball?.removeFromParent()
        let r = ballRadius
        let node = SKShapeNode(circleOfRadius: r)
        node.fillColor = .white; node.strokeColor = SKColor(white: 0.65, alpha: 1); node.lineWidth = 1
        node.position = pt(GameTable.shared.ballStart.x, GameTable.shared.ballStart.y)
        node.zPosition = 5
        let body = SKPhysicsBody(circleOfRadius: r)
        body.isDynamic = true; body.mass = ballMass
        body.restitution = 0.18; body.friction = 0.1; body.linearDamping = 0.1
        body.usesPreciseCollisionDetection = true
        body.categoryBitMask = Cat.ball
        body.collisionBitMask = Cat.wall | Cat.flipper | Cat.bumper | Cat.sling
        body.contactTestBitMask = Cat.bumper | Cat.sling | Cat.drain
        node.physicsBody = body
        ball = node
        addChild(node)
        awaitingLaunch = true
        pushModel()
    }

    private func launch() {
        guard awaitingLaunch, let b = ball?.physicsBody else { return }
        awaitingLaunch = false
        b.velocity = CGVector(dx: 0, dy: field.height * launchSpeedFrac)
        pushModel()
    }

    // MARK: Flippers / input

    private func flip(left: Bool, up: Bool) {
        guard let node = left ? leftFlipper : rightFlipper else { return }
        let target = left ? (up ? leftFlip : leftRest) : (up ? rightFlip : rightRest)
        node.removeAllActions()
        node.run(.rotate(toAngle: target, duration: flipDuration, shortestUnitArc: true))
        if up && hapticsEnabled { Haptics.light() }
    }

    override func touchesBegan(_ touches: Set<UITouch>, with event: UIEvent?) {
        for t in touches {
            if awaitingLaunch { launch(); continue }
            flip(left: t.location(in: self).x < size.width / 2, up: true)
        }
    }
    override func touchesEnded(_ touches: Set<UITouch>, with event: UIEvent?) {
        for t in touches { flip(left: t.location(in: self).x < size.width / 2, up: false) }
    }
    override func touchesCancelled(_ touches: Set<UITouch>, with event: UIEvent?) {
        flip(left: true, up: false); flip(left: false, up: false)
    }

    // MARK: Contacts

    func didBegin(_ contact: SKPhysicsContact) {
        let other = (contact.bodyA.categoryBitMask == Cat.ball) ? contact.bodyB : contact.bodyA
        switch other.categoryBitMask {
        case Cat.bumper: hitKicker(other.node, magnitude: bumperImpulse, points: bumperScore)
        case Cat.sling:  hitKicker(other.node, magnitude: slingImpulse, points: slingScore)
        case Cat.drain:  drainBall()
        default: break
        }
    }

    private func hitKicker(_ node: SKNode?, magnitude: CGFloat, points: Int) {
        guard let node = node, let bb = ball?.physicsBody, let bn = ball else { return }
        let dx = bn.position.x - node.position.x, dy = bn.position.y - node.position.y
        let len = max(hypot(dx, dy), 0.001)
        bb.applyImpulse(CGVector(dx: dx / len * magnitude, dy: dy / len * magnitude))
        score += points; model?.score = score
        node.run(.sequence([.scale(to: 1.18, duration: 0.05), .scale(to: 1.0, duration: 0.09)]))
        if hapticsEnabled { Haptics.light() }
    }

    private func drainBall() {
        guard let b = ball else { return }
        b.removeFromParent(); ball = nil
        ballsLeft -= 1
        if ballsLeft <= 0 { isOver = true; pushModel() } else { spawnBall() }
    }

    private func pushModel() {
        model?.score = score
        model?.ballsLeft = ballsLeft
        model?.awaitingLaunch = awaitingLaunch
        model?.isOver = isOver
    }
}
